import{_ as t,o,c as r,ak as a,by as n}from"./chunks/framework.C44GrXwr.js";const p=JSON.parse('{"title":"Local Server","description":"","frontmatter":{},"headers":[],"relativePath":"documentation/local-server/local-server.md","filePath":"documentation/local-server/local-server.md","lastUpdated":1772776319000}'),i={name:"documentation/local-server/local-server.md"};function s(l,e,c,d,h,g){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="local-server" tabindex="-1">Local Server <a class="header-anchor" href="#local-server" aria-label="Permalink to “Local Server”">​</a></h1><p>The Local Server feature allows the extension to communicate with a locally hosted server to perform advanced automation tasks, such as email operations and local data processing.</p><p>To configure the server connection to extension, see the <a href="/documentation/settings.html#extension-server">Extension Server Settings</a> page.</p><p><img src="'+n+'" alt="Server Image"></p><h2 id="installation" tabindex="-1">📥 Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “📥 Installation”">​</a></h2><p>Follow these steps to set up and run the Local Server on your machine.</p><h3 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to “Download”">​</a></h3><table tabindex="0"><thead><tr><th>Platform</th><th>Download Link</th><th>Version</th></tr></thead><tbody><tr><td><strong>Windows</strong></td><td><a href="/edf-server-v1.0.0.zip">Download EDF Server</a></td><td>v1.0.0</td></tr></tbody></table><h3 id="how-to-run" tabindex="-1">How to Run <a class="header-anchor" href="#how-to-run" aria-label="Permalink to “How to Run”">​</a></h3><ol><li><strong>Download</strong>: Click the link above to download the <code>edf-server-v1.0.0.zip</code> file.</li><li><strong>Extract</strong>: Right-click the downloaded zip file and select <strong>Extract All...</strong> to unzip the contents.</li><li><strong>Run</strong>: Open the extracted folder and double-click the <code>edf-server.exe</code> program.</li><li><strong>Command Window</strong>: A CMD (Command Prompt) window will open, indicating the server is running.</li><li><strong>Browser Access</strong>: The server interface will automatically open in your default browser at <a href="http://127.0.0.10:8080/" target="_blank" rel="noreferrer">http://127.0.0.10:8080/</a>.</li></ol><h3 id="api-configuration" tabindex="-1">API Configuration <a class="header-anchor" href="#api-configuration" aria-label="Permalink to “API Configuration”">​</a></h3><p>To enable communication between the extension and the local server, you must configure the API settings:</p><ol><li><strong>Open API Settings</strong>: Navigate to the server&#39;s API settings page: <a href="http://127.0.0.10:8080/settings/api" target="_blank" rel="noreferrer">http://127.0.0.10:8080/settings/api</a>.</li><li><strong>Enable Public API</strong>: Ensure the <strong>Public API</strong> toggle is turned <strong>ON</strong> to allow the extension to access the server.</li><li><strong>API Authorization</strong>: In the <strong>API Authorization</strong> section, you will see the key <code>X-API-Token</code>.</li><li><strong>Copy Value</strong>: Click the copy icon next to the <strong>Value</strong> field to copy your authorization token.</li><li><strong>Configure Extension</strong>: Open the extension&#39;s <strong><a href="/documentation/settings.html#extension-server">Settings</a></strong> page, navigate to the <strong>Extension Server</strong> section, and paste the token into the <strong>X-API-Token</strong> field.</li></ol><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Keep the CMD window open while using the extension&#39;s local server features. Closing the window will stop the server.</p></div><h2 id="server-interface" tabindex="-1">🖥️ Server Interface <a class="header-anchor" href="#server-interface" aria-label="Permalink to “🖥️ Server Interface”">​</a></h2><p>The Local Server dashboard provides several tools to manage your automation environment.</p><ul><li><strong>Dashboard</strong>: View overall server status, uptime, and active connections.</li><li><strong><a href="./mail-accounts.html">Mail Accounts</a></strong>: Add and configure the email accounts that the extension will interact with.</li><li><strong>API Settings</strong>: Manage API Authorization tokens and toggle public API access.</li><li><strong>Audit Logs</strong>: Review a detailed history of all requests and actions performed by the server for debugging and security monitoring.</li></ul><h2 id="where-to-use" tabindex="-1">🚀 Where to Use <a class="header-anchor" href="#where-to-use" aria-label="Permalink to “🚀 Where to Use”">​</a></h2><p>The Local Server is utilized by specific field types that require system-level or network-level access for automation tasks.</p><p>Currently, the following field types depend on the Local Server:</p><ul><li><strong><a href="/documentation/field-types/local-server/get-mail-from-local-server.html">Get Mail from Local Server</a></strong></li><li><strong><a href="/documentation/field-types/local-server/send-mail-from-local-server.html">Send Mail from Local Server</a></strong></li></ul><p>For a complete overview of all available field types, visit the <strong><a href="/documentation/form-fields/field-types.html#local-server">Local Server Field Types</a></strong> section.</p><h2 id="security-considerations" tabindex="-1">🔒 Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to “🔒 Security Considerations”">​</a></h2><p>Your privacy and data security are our top priorities.</p><ul><li><strong>Local Processing</strong>: All data processed by the Local Server stays on your machine.</li><li><strong>No Data Collection</strong>: We do not collect, store, or transmit any of your data to external servers.</li><li><strong>Privacy First</strong>: The server operates entirely within your local environment, ensuring that sensitive information like email content or automation data never leaves your computer.</li></ul>',25)])])}const v=t(i,[["render",s]]);export{p as __pageData,v as default};
